import{f as t,ab as a,p as i,t as n}from"./chunks/framework.Bi8ho8sH.js";const g=JSON.parse('{"title":"Tingweek overview","description":"This gives an overview of the HUNT Cloud Tingweek.","frontmatter":{"title":"Tingweek overview","category":"Tingweek","permalink":"/govern-science/tingweek/overview","outline":1,"description":"This gives an overview of the HUNT Cloud Tingweek."},"headers":[],"relativePath":"govern-science/tingweek/about.md","filePath":"govern-science/tingweek/about.md"}'),s={name:"govern-science/tingweek/about.md"};function o(r,e,l,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="about-tingweeks" tabindex="-1">About Tingweeks <a class="header-anchor" href="#about-tingweeks" aria-label="Permalink to &quot;About Tingweeks&quot;">​</a></h1><p><strong>We appoint time three times per year to meet for information, feedback and discussions on how to develop the services in HUNT Cloud to better elevate science. We call these gatherings Tings.</strong></p><p>We arrange a layered set of Tings for distinct groups in our community. The meetings are spread out over one week in the winter, spring and autumn. We call these weeks Tingweeks.</p><div class="tip custom-block"><p class="custom-block-title">Next Tingweek</p><p><a href="/govern-science/tingweek/dates">Click here</a> to see the dates for upcoming Tingweeks.</p></div><nav class="table-of-contents"><ul><li><a href="#the-different-tings">The different Tings</a><ul><li><a href="#labting">Labting</a></li><li><a href="#admin-ting">Admin ting</a></li><li><a href="#data-controller-ting">Data controller ting</a></li></ul></li><li><a href="#schedule">Schedule</a><ul><li><a href="#dates">Dates</a></li><li><a href="#times">Times</a></li></ul></li><li><a href="#agenda">Agenda</a></li><li><a href="#resolutions">Resolutions</a></li><li><a href="#frequently-asked-questions">Frequently asked questions</a></li><li><a href="#historical-development">Historical development</a></li></ul></nav><h2 id="the-different-tings" tabindex="-1">The different Tings <a class="header-anchor" href="#the-different-tings" aria-label="Permalink to &quot;The different Tings&quot;">​</a></h2><p>We appoint time for three different Tings during the Tingweek to elevate voices and collective knowledge from distinct groups within our HUNT Cloud community. All users and administrators in HUNT Cloud are welcome to participate in all Tings.</p><h3 id="labting" tabindex="-1">Labting <a class="header-anchor" href="#labting" aria-label="Permalink to &quot;Labting&quot;">​</a></h3><p>This is our allting were we focuses on <strong>user experiences inside labs</strong>. All active lab users, lab leaders and lab coordinators are invited for information, feedback and discussions on all aspects of existing, planned and future services. <a href="/do-science/community/labting">Read more about the Labting</a> in our do science section.</p><h3 id="admin-ting" tabindex="-1">Admin ting <a class="header-anchor" href="#admin-ting" aria-label="Permalink to &quot;Admin ting&quot;">​</a></h3><p>This is the Ting where we focuses on <strong>administrative aspects</strong> in labs and data spaces. All data space administrators, lab leaders and lab coordinators are invited for information, feedback and discussion on administration of data, technologies and training. The Admin ting does also cover financial aspects related to prices, invoices and services specifications. Ting resolutions are also announced in this Ting.</p><h3 id="data-controller-ting" tabindex="-1">Data controller ting <a class="header-anchor" href="#data-controller-ting" aria-label="Permalink to &quot;Data controller ting&quot;">​</a></h3><p>This is the Ting where we initiate <strong>cross-organizational dialogue on privacy, security and ethics</strong> in HUNT Cloud. All privacy and security contacts, and data space compliance administrators, are invited.</p><h2 id="schedule" tabindex="-1">Schedule <a class="header-anchor" href="#schedule" aria-label="Permalink to &quot;Schedule&quot;">​</a></h2><h3 id="dates" tabindex="-1">Dates <a class="header-anchor" href="#dates" aria-label="Permalink to &quot;Dates&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Ting dates</p><p><a href="/govern-science/tingweek/dates">Click here</a> to see past and future Ting dates.</p></div><h3 id="times" tabindex="-1">Times <a class="header-anchor" href="#times" aria-label="Permalink to &quot;Times&quot;">​</a></h3><p>Our Tingweeks are scheduled over one week in winter, spring and autumn.</p><p>The winter Ting is scheduled mid February the week before Norway&#39;s winter holidays (vinterferie). The spring Ting is scheduled in late May / early June. The autumn Ting in scheduled in the second half of October the week after Norway&#39;s autumn holiday (høstferie).</p><p>Individual Tings are scheduled over the week on fixed time slots. The current schedule is as follows: Labting is held on Tuesdays 2-4 pm CET, Admin ting on Wednesdays 9-11 am CET and Data controller ting on Wednesdays 1-3 pm CET.</p><h2 id="agenda" tabindex="-1">Agenda <a class="header-anchor" href="#agenda" aria-label="Permalink to &quot;Agenda&quot;">​</a></h2><p>All users are welcome to propose agenda items for the next meetings. <a href="/govern-science/tingweek/faq">Click here</a> to see past agendas.</p><h2 id="resolutions" tabindex="-1">Resolutions <a class="header-anchor" href="#resolutions" aria-label="Permalink to &quot;Resolutions&quot;">​</a></h2><p>We document applied and intended development changes to our services in the form of resolutions. Resolutions from previous Tingweeks are available in our resolutions page. All administrators are welcome to propose resolutions for the next meeting.</p><div class="tip custom-block"><p class="custom-block-title">Resolutions</p><p><a href="/govern-science/tingweek/resolutions">Click here</a> for past resolutions.</p></div><p>Resolutions consist of two parts: (i) the introductory sentence that states the context of the resolution, and (ii) one to several operational clauses that describe the recommended action.</p><h2 id="frequently-asked-questions" tabindex="-1">Frequently asked questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently asked questions&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">FAQ</p><p><a href="/govern-science/tingweek/faq">Click here</a> to read our Tingweek FAQ.</p></div><h2 id="historical-development" tabindex="-1">Historical development <a class="header-anchor" href="#historical-development" aria-label="Permalink to &quot;Historical development&quot;">​</a></h2><p>We aim to continuously evolve the Tingweeks a long with evolving scientific and administrative needs:</p><ul><li>The Financial ting and Admin ting was merged in Tingweek #18, and Lagtun resolutions was renamed Ting resolutions.</li><li>The Coordinator ting changed name to Admin ting, and Lagtun changed name to Financial ting in Tingweek #14.</li><li>The original Coordinator ting changed name to Data space ting in Tingweek #5 to reflect contractual roles in the new services model.</li><li>We published a Ting report for the first Tingweeks: <a href="https://assets.hdc.ntnu.no/assets/tingweek/hunt-cloud-tingweek6-report.pdf" target="_blank" rel="noreferrer">Ting report #6 (2022-05)</a>, <a href="https://assets.hdc.ntnu.no/assets/tingweek/hunt-cloud-tingweek4-report.pdf" target="_blank" rel="noreferrer">Ting report #4 (2021-10)</a>, <a href="https://assets.hdc.ntnu.no/assets/tingweek/hunt-cloud-tingweek3-report.pdf" target="_blank" rel="noreferrer">Ting report #3 (2021-05)</a>, <a href="https://assets.hdc.ntnu.no/assets/tingweek/hunt-cloud-tingweek2-report.pdf" target="_blank" rel="noreferrer">Ting report #2 (2021-02)</a>, <a href="https://assets.hdc.ntnu.no/assets/tingweek/hunt-cloud-tingweek1-report.pdf" target="_blank" rel="noreferrer">Ting report #1 (2020-10)</a>.</li><li>The Tingweek was introduced in 2020 at the time we introduced our price model.</li></ul>',31)])])}const p=t(s,[["render",o]]);export{g as __pageData,p as default};
